// ============================================================
// pages/Login.jsx — Merchant Login Page
// ============================================================
// Authenticates merchant using email + password.
// On success: stores JWT in localStorage, redirects to /dashboard
// ============================================================

import React, { useState } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { authAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import "../styles/auth.css";

function Login() {
  const navigate  = useNavigate();
  const location  = useLocation();
  const { login } = useAuth();  // Global auth context

  // Pick up success message from Register redirect
  const successMessage = location.state?.message || "";

  const [email,    setEmail]    = useState("");
  const [password, setPassword] = useState("");
  const [error,    setError]    = useState("");
  const [loading,  setLoading]  = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!email || !password) {
      setError("Please enter email and password");
      return;
    }

    setLoading(true);
    try {
      // Call POST /api/auth/login
      const res = await authAPI.login(email, password);
      const { access_token, role } = res.data;

      // Save to global context + localStorage
      login({ email }, access_token, role);

      // Redirect to merchant dashboard
      navigate("/dashboard");
    } catch (err) {
      setError(err.response?.data?.detail || "Invalid email or password");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-logo">
          <div className="brand-name">PayOnboard</div>
          <div className="brand-tagline">Merchant Onboarding Platform</div>
        </div>

        <h1 className="auth-title">Welcome Back</h1>
        <p className="auth-subtitle">Sign in to your merchant account</p>

        {/* Success message from registration */}
        {successMessage && <div className="alert alert-success">{successMessage}</div>}

        {error && <div className="alert alert-error">{error}</div>}

        <form onSubmit={handleSubmit} noValidate>
          <div className="form-group">
            <label className="form-label">Email Address</label>
            <input
              className="form-input"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="business@example.com"
              autoComplete="email"
            />
          </div>

          <div className="form-group">
            <label className="form-label">Password</label>
            <input
              className="form-input"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              autoComplete="current-password"
            />
          </div>

          <button className="btn-primary" type="submit" disabled={loading}>
            {loading ? "Signing In..." : "Sign In"}
          </button>
        </form>

        <p className="auth-footer">
          Don't have an account? <Link to="/register">Register your business</Link>
        </p>
        <p className="auth-footer" style={{ marginTop: "0.5rem" }}>
          Are you an admin? <Link to="/admin/login">Admin Login</Link>
        </p>
      </div>
    </div>
  );
}

export default Login;
